+@page "/shipments/{TrackingNumber}"
+@rendermode InteractiveAuto
+@implements IAsyncDisposable
+@inject ShipmentServiceBase ShipmentService
+@inject ILogger<ShipmentTracker> Logger
+
+<PageTitle>Shipment @TrackingNumber</PageTitle>
+
+@if (error is not null)
+{
+    <div class="alert alert-danger">
+        <p>@error</p>
+        <button class="btn btn-outline-danger btn-sm" @onclick="LoadAsync">Retry</button>
+    </div>
+}
+else if (shipment is null)
+{
+    <div class="alert alert-info">
+        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
+    </div>
+}
+else
+{
+    @if (isLoading)
+    {
+        <p><em>Refreshing…</em></p>
+    }
+
+    <h3>Shipment @shipment.TrackingNumber</h3>
+
+    <dl>
+        <dt>Status</dt>
+        <dd>@shipment.Status</dd>
+
+        <dt>Location</dt>
+        <dd>@shipment.Location</dd>
+
+        <dt>Estimated Delivery</dt>
+        <dd>@shipment.EstimatedDelivery.ToString("D")</dd>
+    </dl>
+
+    <h4>Status Updates</h4>
+    <ul>
+        @foreach (var update in shipment.Updates)
+        {
+            <li><strong>@update.Timestamp.ToString("g")</strong> — @update.Description</li>
+        }
+    </ul>
+}
+
+@code {
+    [Parameter] public string TrackingNumber { get; set; } = default!;
+
+    private CancellationTokenSource? cts;
+    private string? loadedTrackingNumber;
+    private ShipmentDetails? shipment;
+    private bool isLoading;
+    private string? error;
+
+    protected override async Task OnParametersSetAsync()
+    {
+        if (string.Equals(TrackingNumber, loadedTrackingNumber, StringComparison.OrdinalIgnoreCase))
+        {
+            return;
+        }
+
+        loadedTrackingNumber = TrackingNumber;
+        await LoadAsync();
+    }
+
+    private async Task LoadAsync()
+    {
+        if (cts is not null)
+        {
+            await cts.CancelAsync();
+            cts.Dispose();
+        }
+
+        cts = new CancellationTokenSource();
+        var cancellationToken = cts.Token;
+
+        error = null;
+        isLoading = true;
+
+        try
+        {
+            var result = await ShipmentService.GetShipmentAsync(TrackingNumber, cancellationToken);
+            shipment = result;
+        }
+        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
+        {
+            // Self-cancellation (parameter change or disposal) — let ComponentBase handle it.
+            throw;
+        }
+        catch (OperationCanceledException ex)
+        {
+            Logger.LogWarning(ex, "Request timed out for shipment {TrackingNumber}", TrackingNumber);
+            error = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
+            error = "Unable to load shipment details. Please try again.";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (cts is not null)
+        {
+            await cts.CancelAsync();
+            cts.Dispose();
+        }
+    }
+}
+

